float dist(Point p1, Point p2, int dim)
{
  int i;
  float result=0.0;
  for (i=0;i<dim;i++)
    result += (p1.coord[i] - p2.coord[i])*(p1.coord[i] - p2.coord[i]);
#ifdef INSERT_WASTE
  float s = waste(result);
  result += s;
  result -= s;
#endif
  return(result);
}

float pgain( long x, Points *points, float z, long int *numcenters, int kmax, bool *is_center, int *center_table, bool *switch_membership, bool isCoordChanged,
							double *serial_t, double *cpu_to_gpu_t, double *gpu_to_cpu_t, double *alloc_t, double *kernel_t, double *free_t)
{	
	double t_start, t_end;
	t_start = gettime();

	int stride	= *numcenters + 1;			
	int K		= *numcenters ;				
	int num		=  points->num;				
	int dim		=  points->dim;				
	int nThread =  num;						

	float *work_mem_h = (float*) malloc(stride * (nThread + 1) * sizeof(float) );
	static float *coord_h = NULL;
	if(coord_h == NULL) {
		coord_h	= (float*) malloc( num * dim * sizeof(float) );
	}

	int count = 0;
	for( int i=0; i<num; i++)
	{
		if( is_center[i] )
		{
			center_table[i] = count++;
		}
	}

	if(isCoordChanged)
	{
		for(int i=0; i<dim; i++)
		{
			for(int j=0; j<num; j++)
			{
				coord_h[ (num*i)+j ] = points->p[j].coord[i];
			}
		}
	}

	t_end = gettime();
	*serial_t += (t_end - t_start)*1000;

	t_start = gettime();

	float *work_mem_d = (float*) malloc(stride * (nThread + 1) * sizeof(float));
	if(work_mem_d == NULL) {
		fprintf(stderr, "Failed to allocate work_mem_d\n");
		exit(EXIT_FAILURE);
	}

	static int *center_table_d = NULL;
	static bool *switch_membership_d = NULL;
	static Point *p_d = NULL;

	if(center_table_d == NULL) {
		center_table_d = (int*) malloc(num * sizeof(int));
		switch_membership_d = (bool*) malloc(num * sizeof(bool));
		p_d = (Point*) malloc(num * sizeof(Point));
		if(center_table_d == NULL || switch_membership_d == NULL || p_d == NULL) {
			fprintf(stderr, "Failed to allocate device memory equivalents\n");
			exit(EXIT_FAILURE);
		}
	}

	t_end = gettime();
	*alloc_t += (t_end - t_start)*1000;

	t_start = gettime();

	if(isCoordChanged)
	{
		memcpy(coord_h, coord_h, num * dim * sizeof(float)); // no-op but keep for structure
	}
	memcpy(center_table_d, center_table, num * sizeof(int));
	memcpy(p_d, points->p, num * sizeof(Point));

	memset(switch_membership_d, 0, num * sizeof(bool));
	memset(work_mem_d, 0, stride * (nThread + 1) * sizeof(float));

	t_end = gettime();
	*cpu_to_gpu_t += (t_end - t_start)*1000;

	t_start = gettime();

	// Parallelize kernel_compute_cost with OpenMP
	#pragma omp parallel for schedule(static)
	for(int tid = 0; tid < num; tid++)
	{
		float *lower = &work_mem_d[tid*stride];

		float retval = 0.0;
		for(int i = 0; i < dim; i++){
			float tmp = coord_h[(i*num)+tid] - coord_h[(i*num)+x];
			retval += tmp * tmp;
		}
		float x_cost = retval * p_d[tid].weight;

		if ( x_cost < p_d[tid].cost )
		{
			switch_membership_d[tid] = true;
			lower[K] += x_cost - p_d[tid].cost;
		}
		else
		{
			lower[center_table_d[p_d[tid].assign]] += p_d[tid].cost - x_cost;
		}
	}

	t_end = gettime();
	*kernel_t += (t_end - t_start)*1000;

	t_start = gettime();

	memcpy(work_mem_h, work_mem_d, stride * (nThread + 1) * sizeof(float));
	memcpy(switch_membership, switch_membership_d, num * sizeof(bool));

	t_end = gettime();
	*gpu_to_cpu_t += (t_end - t_start)*1000;

	int number_of_centers_to_close = 0;
	float gl_cost_of_opening_x = z;
	float *gl_lower = &work_mem_h[stride * nThread];

	for(int i=0; i < num; i++)
	{
		if( is_center[i] )
		{
			float low = z;
		    for( int j = 0; j < num; j++ )
			{
				low += work_mem_h[ j*stride + center_table[i] ];
			}

		    gl_lower[center_table[i]] = low;

		    if ( low > 0 )
			{
				++number_of_centers_to_close;
				work_mem_h[i*stride+K] -= low;
		    }
		}
		gl_cost_of_opening_x += work_mem_h[i*stride+K];
	}

	if ( gl_cost_of_opening_x < 0 )
	{
		for(int i = 0; i < num; i++)
		{
			bool close_center = gl_lower[center_table[points->p[i].assign]] > 0 ;
			if ( switch_membership[i] || close_center )
			{
				points->p[i].cost = dist(points->p[i], points->p[x], dim) * points->p[i].weight;
				points->p[i].assign = x;
			}
		}

		for(int i = 0; i < num; i++)
		{
			if( is_center[i] && gl_lower[center_table[i]] > 0 )
			{
				is_center[i] = false;
			}
		}

		if( x >= 0 && x < num)
		{
			is_center[x] = true;
		}
		*numcenters = *numcenters + 1 - number_of_centers_to_close;
	}
	else
	{
		gl_cost_of_opening_x = 0;
	}

	free(work_mem_h);
	free(work_mem_d);

	t_end = gettime();
	*serial_t += (t_end - t_start)*1000;

	return -gl_cost_of_opening_x;
}

